def test_wire_transfer_below_threshold_queued(api_client, fresh_2fa_token, new_idempotency_key):
    headers = {
        "Authorization": f"Bearer {fresh_2fa_token}",
        "Idempotency-Key": new_idempotency_key,
    }
    payload = {
        "amount": 50000,
        "currency": "USD",
        "destination_account": "<valid_dest_account>",
    }
    resp = api_client.post("/transfers/wire", json=payload, headers=headers)
    assert resp.status_code in (200, 201), f"Unexpected status: {resp.status_code}"
    body = resp.json()
    assert body.get("status") == "queued"
    assert "transfer_id" in body
    assert body.get("compliance_check") == "started"

def test_wire_transfer_stale_2fa_returns_401(api_client, stale_2fa_token, new_idempotency_key):
    headers = {
        "Authorization": f"Bearer {stale_2fa_token}",
        "Idempotency-Key": new_idempotency_key,
    }
    payload = {
        "amount": 50000,
        "currency": "USD",
        "destination_account": "<valid_dest_account>",
    }
    resp = api_client.post("/transfers/wire", json=payload, headers=headers)
    assert resp.status_code == 401
    body = resp.json()
    assert "2fa" in body.get("error", "").lower() or "authentication" in body.get("error", "").lower()

def test_wire_transfer_at_100k_boundary_requires_manual_review(api_client, fresh_2fa_token, new_idempotency_key):
    headers = {
        "Authorization": f"Bearer {fresh_2fa_token}",
        "Idempotency-Key": new_idempotency_key,
    }
    payload = {
        "amount": 100000,
        "currency": "USD",
        "destination_account": "<valid_dest_account>",
    }
    resp = api_client.post("/transfers/wire", json=payload, headers=headers)
    assert resp.status_code == 202, f"Expected 202, got {resp.status_code}"
    body = resp.json()
    assert body.get("status") in ("pending_review", "manual_review")
    assert "transfer_id" in body

